solutions.javascript:
// Import express module
const express = require('express');

// Create an express app
const app = express();

// Use express Router to define the route
const router = express.Router();

// Use express.Router().param() to validate the ':name' parameter
router.param('name', (req, res, next, value) => {
  if (typeof value !== 'string') {
    return res.status(400).send({ error: 'Invalid name' });
  }
  req.name = value;
  next();
});

// Define a function to handle the GET request to '/users/:name'
router.get('/users/:name', (req, res) => {
  // Return a JSON object with a 'message' property containing the provided name
  res.send({ message: req.name });
});

// Use the router to handle GET requests to '/users/:name'
app.use('/users/:name', router);

// Start the server
app.listen(3000, () => {
  console.log('Server started on port 3000');
});
